VALUES
  ('medical-tech-moex-07648', 'medical-tech', 'medical-tech-moex-107-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '有關肝炎病毒的敘述，下列何者錯誤？', '["HBV、HCV及HDV主要為血液媒介傳染（blood borne）之病毒", "HEV為RNA病毒，主要感染人類而不會感染其它動物", "HAV屬於小核糖核酸病毒科（Picornaviridae），而HEV則屬於肝炎病毒科（Hepeviridae）", "孕婦罹患HEV時有較高的死亡率，尤其是懷孕第三期（third trimester）的孕婦"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:31+00:00", "source_pdf_sha1": "4b95d358b69a", "answer_pdf_sha1": "7245a4b6cf7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107020", "c": "308", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "107", "exam_name": "107年第一次專技人員高等考試醫師牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師、職能治療師、呼吸治療師、獸醫師考試、107年...", "original_question_number": 71, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
